const e=JSON.parse('{"key":"v-f6e4cd8c","path":"/posts/%E6%B5%8F%E8%A7%88%E5%99%A8%E7%9A%84%E7%BC%93%E5%AD%98%E3%80%81%E8%B7%A8%E5%9F%9F%E4%B8%8E%E5%AE%89%E5%85%A8.html","title":"你可以不用但不能不懂：浏览器的缓存、跨域与安全","lang":"zh-CN","frontmatter":{"title":"你可以不用但不能不懂：浏览器的缓存、跨域与安全","isTimeLine":true,"date":"2026-03-12T00:00:00.000Z","category":["前端"],"tag":["性能优化","浏览器原理"]},"headers":[{"level":3,"title":"浏览器的资源一般存储在哪里","slug":"浏览器的资源一般存储在哪里","link":"#浏览器的资源一般存储在哪里","children":[]},{"level":3,"title":"浏览器的本地缓存？","slug":"浏览器的本地缓存","link":"#浏览器的本地缓存","children":[]},{"level":3,"title":"对浏览器缓存机制的了解？","slug":"对浏览器缓存机制的了解","link":"#对浏览器缓存机制的了解","children":[]},{"level":3,"title":"什么是同源策略？","slug":"什么是同源策略","link":"#什么是同源策略","children":[]},{"level":3,"title":"怎么解决跨域问题？","slug":"怎么解决跨域问题","link":"#怎么解决跨域问题","children":[]},{"level":3,"title":"浏览器安全机制？","slug":"浏览器安全机制","link":"#浏览器安全机制","children":[]},{"level":3,"title":"浏览器的垃圾回收机制？","slug":"浏览器的垃圾回收机制","link":"#浏览器的垃圾回收机制","children":[]},{"level":3,"title":"链接","slug":"链接","link":"#链接","children":[]}],"git":{"createdTime":1773252729000,"updatedTime":1773252729000,"contributors":[{"name":"liunal","email":"liunal","commits":1}]},"readingTime":{"minutes":11.02,"words":3306},"filePathRelative":"posts/浏览器的缓存、跨域与安全.md","localizedDate":"2026年3月12日","excerpt":"<h3> 浏览器的资源一般存储在哪里</h3>\\n<ol>\\n<li>资源存储的位置一共有三种，从高到低依次是<code>Service worker、Memory Cache、Disk Cache</code></li>\\n<li><code>service worker</code>：运行在主线程之外，可以完成离线缓存、消息推送、网络代理的功能。可以自由控制缓存哪些文件，怎么读取缓存。当 Service Worker 没有命中缓存的时候，需要去调用 fetch 函数获取数据。</li>\\n<li><code>Memory Cache</code>：内存缓存，它的效率最快，但是它会随着进程的释放而释放。一旦关闭tab页面，内存的缓存也被释放了。</li>\\n<li><code>Disk Cache</code>: 存储在硬盘的缓存，对比于内存缓存，读取的速度慢一些，特点是容量与时效性上更长。它会根据 HTTP请求头中的字段判断哪些资源需要缓存，哪些资源可以不请求直接使用，哪些资源已经过期需要重新请求。</li>\\n</ol>"}');export{e as data};
